+fn unique_temp_dir(name: &str) -> PathBuf {
+    let mut path = std::env::temp_dir();
+    path.push("franken_engine_asupersync_contract_matrix");
+    path.push(name);
+    path.push(Uuid::now_v7().to_string());
+    fs::create_dir_all(&path).expect("create temp dir");
+    path
