+fn write_fake_asupersync_root(root: &Path, decision_kernel_version: &str, with_examples: bool) {
+    write_fake_asupersync_root_with_frankenlab(
+        root,
+        decision_kernel_version,
+        with_examples,
+        "0.2.7",
+        "0.2.7",
+        "src/main.rs",
+    );
+}
