+fn make_config() -> FreshnessConfig {
+    let mut authorized = BTreeSet::new();
+    authorized.insert("ops-admin-01".to_string());
+
+    let mut override_eligible = BTreeSet::new();
+    override_eligible.insert(OperationType::ExtensionActivation);
