+    let dist = m.floyd_warshall().unwrap();
+    // dist[0][2] should be 3 (via 0→1→2), not 10
+    assert_eq!(dist.get(0, 2), TropicalWeight::finite(3));
+    // triangle inequality: dist[i][j] <= dist[i][k] + dist[k][j]
+    for i in 0..3 {
